import { useEffect, useRef } from 'react';
import { createFocusTrap, type FocusTrapOptions, type FocusTrap } from '@o9ds/core';

export type UseFocusTrapOptions = Omit<FocusTrapOptions, 'container'> & {
  active: boolean;
};

export function useFocusTrap(
  containerRef: React.RefObject<HTMLElement | null>,
  options: UseFocusTrapOptions,
): void {
  const trapRef = useRef<FocusTrap | null>(null);

  // Keep options in a ref so the effect closure always has the latest values
  // without triggering unnecessary activations on every render.
  const optionsRef = useRef(options);
  optionsRef.current = options;

  useEffect(() => {
    if (!trapRef.current) {
      trapRef.current = createFocusTrap();
    }
    const trap = trapRef.current;

    if (options.active && containerRef.current) {
      const { active: _active, ...rest } = optionsRef.current;
      trap.activate({ container: containerRef.current, ...rest });
    } else {
      trap.deactivate();
    }

    return () => {
      trap.deactivate();
    };
    // Callbacks are read via optionsRef so they are intentionally omitted from deps.
  }, [
    options.active,
    containerRef,
    options.initialFocus,
    options.returnFocusOnDeactivate,
    options.escapeDeactivates,
    options.allowOutsideClick,
  ]);
}
